async (page) => {
  // Click east to move toward Wife's tent (260, 229) from current (195, 200)
  await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: 1100, clientY: 450, bubbles: true }));
  });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? { x: s.player_position.x, y: s.player_position.y } : null;
  });
  return JSON.stringify(pos);
}

